/* C++ Program for Bad Character Heuristic of Boyer
Moore String Matching Algorithm */
#include <bits/stdc++.h>
using namespace std;
#define NO_OF_CHARS 256
// The preprocessing function for Boyer Moore's
// bad character heuristic
void badCharHeuristic(string str, int size,
int badchar[NO_OF_CHARS])
{
int i;
// Initialize all occurrences as -1
for (i = 0; i < NO_OF_CHARS; i++)
badchar[i] = -1;
// Fill the actual value of last occurrence
// of a character
for (i = 0; i < size; i++)
badchar[(int)str[i]] = i;
}
/* A pattern searching function that uses Bad
Character Heuristic of Boyer Moore Algorithm */
void search(string txt, string pat)
{
int m = pat.size();
int n = txt.size();
int badchar[NO_OF_CHARS];
/* Fill the bad character array by calling
the preprocessing function badCharHeuristic()
for given pattern */
badCharHeuristic(pat, m, badchar);
int s = 0; // s is shift of the pattern with
// respect to text
while (s <= (n - m)) {
int j = m - 1;
/* Keep reducing index j of pattern while
characters of pattern and text are
matching at this shift s */
while (j >= 0 && pat[j] == txt[s + j])
j--;
/* If the pattern has been matched completely, then print
starting index 's' */
if (j == -1) {
printf("%d\n", s);
}
else {
// Shift the pattern to the right for next comparison
s += max(1, j - badchar[txt[s + j]]);
}
}
}

/* Driver code */
int main()
{
string txt = "ABAAABCD";
string pat = "ABC";
search(txt, pat);
return 0;
}

class Solution:
    def solve(self, txt, pat):
        n = len(txt)
        m = len(pat)

        if m > n:
            return []

        # Precompute the bad character heuristic
        last_occurrence = {char: -1 for char in set(txt)}
        for i in range(n):
            last_occurrence[txt[i]] = i

        matches = []
        i = m - 1
        while i < n:
            j = m - 1
            k = i
            while j >= 0 and txt[k] == pat[j]:
                k -= 1
                j -= 1

            if j < 0:
                matches.append(k + 1)
                shift = max(1, k - last_occurrence.get(txt[k], -2))
            else:
                shift = max(1, j - last_occurrence.get(txt[k], -2))

            i += shift

        return matches
